// For license information, see `https://assets.adobedtm.com/a0f49f083264/354aaa9a6a3e/a7e3e93bb08c/RCb4f62cea8a484e789cf477a784cb7993-source.js`.
_satellite.__registerScript('https://assets.adobedtm.com/a0f49f083264/354aaa9a6a3e/a7e3e93bb08c/RCb4f62cea8a484e789cf477a784cb7993-source.min.js', "<style>\n  #custom-gladly-chat-button {\n    position: fixed;\n    bottom: 20px;\n    right: 20px;\n    height: 70px;\n    width: 70px;\n    cursor: pointer;\n    background-repeat: no-repeat;\n    z-index: 200;\n    display: none;\n  }\n  \n  #custom-gladly-chat-button.gladly-show {\n    display: block;\n  }\n  \n  #custom-gladly-chat-button .unread-dot {\n    visibility: hidden;\n  }\n  \n  #custom-gladly-chat-button.gladly-unread .unread-dot {\n    background-color: #D62727;\n    border-radius: 50%;\n    display: inline;\n    height: 8px;\n    position: absolute;\n    right: 20px;\n    top: 17px;\n    visibility: visible;\n    width: 8px;\n    z-index: 201;\n  }\n  \n  #gladlyChat_container #gladlyStartChatButton, #gladlyChat_container [data-aid='selfService-header'] div {\n    font-weight: normal !important;\n  }\n\n  \n  #gladlyChat_container .minimizedChatButtonSelector {\n    display:none !important;\n  }\n  \n  \n  .for-you-container .campaign-message {\n    text-align: right;\n    margin-top: 20px;\n    font-family: \"LeJeuneDeck-Regular\", \"Times New Roman\", Times, serif;\n    font-size: 1.125rem;\n  }\n  \n  .for-you-container .campaign-message:hover {\n    text-decoration: underline;\n    cursor: pointer;\n  }\n  \n  @media screen and (max-width: 767px) {\n    #custom-gladly-chat-button {\n        display: none;\n    }\n  }\n  \n</style>\n<script>\n\nvar baseUrl = '//' + window.location.hostname + Urls.staticPath + 'images/';\nvar appId = 'ralphlauren.com';\n  \n//get hierarchy that contains 'watches' for all watch and jewelry pages\nvar pageLevelValues = _satellite.getVar('pageHierarchy');\nvar jewelryPages = 'watches';\nvar jpSubstring = pageLevelValues.includes(jewelryPages);\n  \n//Alternate app ids\nif (_satellite.getVar('isCA')) {\n    appId = 'ralphlauren.com-ca';\n} else if (_satellite.getVar('pageLevel2').match(/decor lighting|furniture|rugs/)) {\n    appId = 'ralphlauren.com-Home';\n} else if (_satellite.getVar('pageType') == 'product' && jpSubstring === true) {\n    appId = 'ralphlauren.com-Jewelry-Watches';\n}\n  \n//window.gladlyConfig = { appId: appId };\n  \nif (_satellite.getVar('isMobile') && _satellite.getVar('gladlyChatStatus') == 'active') {\n    $('#custom-gladly-chat-button').css('display','block');\n}\n\nGladly.init({ appId: appId }).then(function() {\n    \n  //Style the default Gladly button and add a click event\n  var startChatButton = document.getElementById('custom-gladly-chat-button');\n  var chatLinks = document.querySelectorAll('.gladly-init, .store-startchat');\n  \n  startChatButton.onclick = function() {Gladly.show()};\n  chatLinks.forEach((link) => {\n    link.onclick = function() {Gladly.show()};\n  });\n\n  //Check initial availability\n  var availability = Gladly.getAvailability();\n  startChatButton.setAttribute('class', availability.toLowerCase());\n\n  //Subscribe to changes in availability and update the button\n  Gladly.on('availability:change', function(availability) {\n    startChatButton.setAttribute('class', availability.toLowerCase());\n  });\n  \n  //Subscribe to changes in conversation status\n  Gladly.on('conversation:started', function(reason) {\n\n    var chat_start_time = new Date();\n    localStorage.setItem('chat_start_time', chat_start_time.getUTCHours() + \":\" + chat_start_time.getUTCMinutes() + \":\" + chat_start_time.getUTCSeconds());\n    localStorage.setItem('chat_status', 'active');\n\n    if (_satellite.getVar('isMobile')) {\n      $('#custom-gladly-chat-button').css('display','block');\n    }\n\n    document.cookie = 'gladly_session' + '=true;path=/';\n    \n    adobeDataLayer.push({\n      \"event\" : \"chatStart\",\n      \"data\": {\n        \"chat\" : {\n          \"start\" : Date.now(),\n          \"status\" : \"active\"\n        }\n      }\n    });\n\n  });\n  \n  Gladly.on('conversation:ended', function(reason) {\n\n      var chat_end_time = new Date();\n      localStorage.setItem('chat_end_time', chat_end_time.getUTCHours() + \":\" + chat_end_time.getUTCMinutes() + \":\" + chat_end_time.getUTCSeconds());\n      localStorage.setItem('chat_status', 'inactive');\n\n      if (_satellite.getVar('isMobile')) {\n        $('#custom-gladly-chat-button').css('display','none');\n      }\n    \n      adobeDataLayer.push({\n        \"event\" : \"chatEnd\",\n        \"data\": {\n          \"chat\" : {\n            \"end\" : Date.now(),\n            \"status\" : \"inactive\"\n          }\n        }\n      });\n\n  });\n});\n  \nvar iconDiv = document.createElement(\"div\");\nvar baseUrl = '//' + window.location.hostname + Urls.staticPath + 'images/';\nvar unreadDotSpan = document.createElement(\"span\");\n\niconDiv.id = 'custom-gladly-chat-button';\niconDiv.style.backgroundImage = \"url(\" + baseUrl + \"chat-icon.svg)\";\niconDiv.classList.add('gladly-init')\n\nunreadDotSpan.classList.add('unread-dot');\niconDiv.appendChild(unreadDotSpan);\n\ndocument.body.appendChild(iconDiv);\n  \n</script>\n");